// Moved from app.js during the page-module split: this observer calls
// applyAiIdentity(), so it must live AND run in the same file the function
// is defined in (app.js executes before this module, so a load-time call
// from there would hit an undefined applyAiIdentity).
(function _setupAiIdentityObserver() {
  let pending = false;
  const trigger = () => {
    if (pending) return;
    pending = true;
    setTimeout(() => {
      pending = false;
      applyAiIdentity().catch(() => {});
    }, 400);
  };
  // Wait for DOM ready before attaching the observer
  const attach = () => {
    if (document.readyState !== 'loading' && document.body) {
      new MutationObserver(trigger).observe(document.body, {
        childList: true, subtree: true,
      });
      // Initial application
      applyAiIdentity().catch(() => {});
    } else {
      setTimeout(attach, 50);
    }
  };
  attach();
})();
